    private Class<?> adapterClass;
    private Object adapterInstance;
    private DateFormat usDateFormat;

    @BeforeEach
    public void setUp() throws Exception {
        adapterClass = Class.forName("com.google.gson.internal.bind.DefaultDateTypeAdapter");

        // Find the DateType class that is NOT an interface (it's a static abstract class)
        Class<?>[] declaredClasses = adapterClass.getDeclaredClasses();
        Class<?> dateTypeClass = null;
        for (Class<?> c : declaredClasses) {
            if ("DateType".equals(c.getSimpleName()) && !c.isInterface()) {
                dateTypeClass = c;
                break;
            }
        }
        if (dateTypeClass == null) {
            throw new IllegalStateException("DateType class not found in DefaultDateTypeAdapter");
        }

