        dateTypeCtor.setAccessible(true);

        // Create a subclass instance of DateType via Proxy is complex since it's a class, not interface
        // Instead, create a subclass dynamically with a minimal anonymous class using reflection Proxy is not possible for class
        // So use a simple subclass via reflection with a dynamic proxy for the method fromDate(Date)

